--
-- Table structure for table `performance_metrics`
--

DROP TABLE IF EXISTS `performance_metrics`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `performance_metrics` (
  `id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT (uuid()),
  `team_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `recorded_date` date NOT NULL,
  `endpoint` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `method` varchar(10) COLLATE utf8mb4_unicode_ci DEFAULT 'GET',
  `response_time_p50_ms` int DEFAULT NULL,
  `response_time_p95_ms` int DEFAULT NULL,
  `response_time_p99_ms` int DEFAULT NULL,
  `throughput_per_minute` int DEFAULT NULL,
  `error_rate` decimal(5,2) DEFAULT NULL,
  `cpu_usage_avg` decimal(5,2) DEFAULT NULL,
  `memory_usage_avg` decimal(5,2) DEFAULT NULL,
  `disk_io_avg` decimal(10,2) DEFAULT NULL,
  `network_io_avg` decimal(10,2) DEFAULT NULL,
  `db_query_time_avg_ms` int DEFAULT NULL,
  `db_connections_avg` int DEFAULT NULL,
  `slow_queries_count` int DEFAULT NULL,
  `page_load_time_ms` int DEFAULT NULL,
  `first_contentful_paint_ms` int DEFAULT NULL,
  `largest_contentful_paint_ms` int DEFAULT NULL,
  `time_to_interactive_ms` int DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `company_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_perf_team` (`team_id`),
  KEY `idx_perf_date` (`recorded_date` DESC),
  KEY `idx_perf_endpoint` (`endpoint`),
  KEY `idx_perf_metrics_team` (`team_id`),
  CONSTRAINT `fk_perf_team` FOREIGN KEY (`team_id`) REFERENCES `teams` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
