--
-- Table structure for table `test_cases`
--

DROP TABLE IF EXISTS `test_cases`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `test_cases` (
  `id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT (uuid()),
  `team_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `name` varchar(500) COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text COLLATE utf8mb4_unicode_ci,
  `test_type` enum('unit','integration','e2e','api','performance','security','manual') COLLATE utf8mb4_unicode_ci DEFAULT 'unit',
  `priority` enum('critical','high','medium','low') COLLATE utf8mb4_unicode_ci DEFAULT 'medium',
  `status` enum('active','obsolete','draft','disabled') COLLATE utf8mb4_unicode_ci DEFAULT 'active',
  `requirement_id` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `file_path` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `class_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `method_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `pass_rate` decimal(5,2) DEFAULT '0.00',
  `execution_count` int DEFAULT '0',
  `last_execution_status` enum('passed','failed','skipped','blocked') COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `last_executed` timestamp NULL DEFAULT NULL,
  `avg_duration_ms` int DEFAULT '0',
  `flakiness_score` decimal(5,2) DEFAULT '0.00',
  `consecutive_failures` int DEFAULT '0',
  `is_flaky` tinyint(1) DEFAULT '0',
  `effectiveness_score` decimal(5,2) DEFAULT '0.00',
  `maintenance_cost_hours` decimal(10,2) DEFAULT '0.00',
  `created_by` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `avg_duration` decimal(8,2) NOT NULL DEFAULT '0.00',
  PRIMARY KEY (`id`),
  KEY `idx_test_cases_team` (`team_id`),
  KEY `idx_test_cases_type` (`test_type`),
  KEY `idx_test_cases_status` (`status`),
  KEY `idx_test_cases_flaky` (`is_flaky`),
  KEY `idx_test_cases_requirement` (`requirement_id`),
  CONSTRAINT `fk_test_cases_team` FOREIGN KEY (`team_id`) REFERENCES `teams` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

